25	class PlayerService {
26	    /**
27	     * Gets the display name for a player.
28	     *
29	     * If the player is anonymous (i.e., the `anonymous` flag is `true`),
30	     * returns a generic name with the player ID. Otherwise, returns the
31	     * player's trimmed name, falling back to a generic name if the name is
32	     * empty or null. A `null` value for `anonymous` is treated as not anonymous
33	     * (equivalent to `false`).
34	     *
35	     * @param player - The player object containing id, name, and anonymous flag
36	     * @param player.id - The unique identifier for the player
37	     * @param player.name - The player's name, can be null
38	     * @param player.anonymous - Whether the player is anonymous; `true` marks
39	     * the player as anonymous, while `false` or a `null` value are treated as
40	     * not anonymous
41	     * @returns The display name for the player
42	     */
43	    private getDisplayName(player: { id: number; name: string | null; anonymous: boolean | null }) {
44	        if (player.anonymous) {
45	            return `Player ${player.id}`;
46	        }
47	
48	        return player.name?.trim() ?? `Player ${player.id}`;
49	    }
50	
51	    /**
52	    * Sanitizes a player object by replacing its name with a display name.
53	    *
54	    * @template T - The player object type extending an object with `id`,
55	    * `name`, and `anonymous` properties.
56	    * @param player - The player object to sanitize.
57	    * @returns A new object with the same properties as the input player, but
58	    * with the `name` property replaced by the display name (guaranteed to be a
59	    * string, not null).
60	    */
61	    private sanitizePlayerName<T extends { id: number; name: string | null; anonymous: boolean | null }>(
62	        player: T,
63	    ): Omit<T, 'name'> & { name: string } {
64	        return {
65	            ...player,
66	            name: this.getDisplayName(player),
67	        };
68	    }
69	
70	    /**
71	     * Get a single player by id
72	     * @param id The numeric ID for the player
73	     * @returns A promise that resolves to the player or undefined if none was
74	     * found
75	     */
76	    async getById(id: number): Promise<PlayerDisplayType | null> {
77	        const where = PlayerWhereUniqueInputObjectSchema.parse({ id });
78	        const player = await prisma.player.findUnique({ where });
79	        return player ? this.sanitizePlayerName(player) : null;
80	    }
