538	    /**
539	     * Builds a hierarchical family tree of players based on the `introducedBy`
540	     * relationship.
541	     *
542	     * Only players who have played at least one game (an outcome with a
543	     * non-null team) are included. Players who have never played are skipped,
544	     * but their place in the introducer chain is preserved: each played
545	     * player's effective parent is the nearest ancestor in the `introducedBy`
546	     * chain who has also played.
547	     *
548	     * After computing effective parents, the tree is further pruned to players
549	     * who either have an effective parent or are themselves the effective
550	     * introducer of at least one other played player. Played players with no
551	     * connection to anyone else are excluded.
552	     *
553	     * A single founder is identified as the first played player with no
554	     * effective parent who is also an effective introducer. Any remaining
555	     * parentless players (orphans) are attached as children of the founder.
556	     *
557	     * If no founder can be identified (e.g. the data contains only circular
558	     * references or no connections at all), an empty virtual root node named
559	     * "Toastboy FC" is returned with no children.
560	     *
561	     * @returns A promise resolving to a single {@link FamilyTreeNodeType} root
562	     * node whose children form the complete introduction tree.
563	     */
564	    async getFamilyTree(): Promise<FamilyTreeNodeType> {
565	        const [allPlayers, playedRows] = await Promise.all([
566	            prisma.player.findMany({
567	                select: {
568	                    id: true,
569	                    name: true,
570	                    anonymous: true,
571	                    introducedBy: true,
572	                },
573	            }),
574	            prisma.outcome.findMany({
575	                where: { team: { not: null } },
576	                select: { playerId: true },
577	                distinct: ['playerId'],
578	            }),
579	        ]);
580	
581	        /** Set of player IDs who have actually played at least one game. */
582	        const playedIds = new Set(playedRows.map((r) => r.playerId));
583	
584	        /**
585	         * Lookup from any player ID to their introducedBy value, used to
586	         * walk up the chain past removed (non-played) players.
587	         */
588	        const introducedByMap = new Map(
589	            allPlayers.map((p) => [p.id, p.introducedBy]),
590	        );
591	
592	        /** Only keep players who have played at least one game. */
593	        const playedPlayers = allPlayers.filter((p) => playedIds.has(p.id));
594	
595	        /**
596	         * For each played player, compute the effective parent: the
597	         * nearest ancestor in the introducer chain who has also played.
598	         */
599	        const effectiveParent = new Map<number, number | null>();
600	        for (const p of playedPlayers) {
601	            let parentId = p.introducedBy;
602	            while (parentId !== null && !playedIds.has(parentId)) {
603	                parentId = introducedByMap.get(parentId) ?? null;
604	            }
605	            effectiveParent.set(p.id, parentId);
606	        }
607	
608	        /**
609	         * Set of played player IDs that are the effective introducer of
610	         * at least one other played player.
611	         */
612	        const introducerIds = new Set(
613	            [...effectiveParent.values()].filter(
614	                (id): id is number => id !== null,
615	            ),
616	        );
617	
618	        /**
619	         * Keep played players who have an effective parent, or who are
620	         * themselves an effective introducer. Excludes played players
621	         * with no connection to anyone else in the tree.
622	         */
623	        const players = playedPlayers.filter(
624	            (p) =>
625	                effectiveParent.get(p.id) !== null ||
626	                introducerIds.has(p.id),
627	        );
628	
629	        /** Map from player id to their tree node. */
630	        const nodeMap = new Map<number, FamilyTreeNodeType>();
631	        for (const p of players) {
632	            nodeMap.set(p.id, {
633	                id: p.id,
634	                name: this.getDisplayName(p),
635	                children: [],
636	            });
637	        }
638	
639	        /**
640	         * Identify the founder: the played player with no effective
641	         * parent who is also an introducer. Any other orphan players
642	         * are attached under the founder.
643	         */
644	        const orphanIds: number[] = [];
645	        let founderId: number | null = null;
646	        for (const p of players) {
647	            if (effectiveParent.get(p.id) === null) {
648	                if (introducerIds.has(p.id) && founderId === null) {
649	                    founderId = p.id;
650	                } else {
651	                    orphanIds.push(p.id);
652	                }
653	            }
654	        }
655	
656	        /** Build the tree by attaching children to parents. */
657	        for (const p of players) {
658	            const node = nodeMap.get(p.id)!;
659	            const parentId = effectiveParent.get(p.id) ?? null;
660	
661	            if (parentId !== null && nodeMap.has(parentId)) {
662	                nodeMap.get(parentId)!.children.push(node);
663	            }
664	        }
665	
666	        /**
667	         * If a founder was found, attach remaining orphans under them
668	         * and return the founder's node as the tree root.
669	         */
670	        if (founderId !== null) {
671	            const founderNode = nodeMap.get(founderId)!;
672	            for (const id of orphanIds) {
673	                founderNode.children.push(nodeMap.get(id)!);
674	            }
675	            return founderNode;
676	        }
677	
678	        /** Fallback: circular references or no connections — return virtual root. */
679	        return { id: 0, name: 'Toastboy FC', children: [] };
680	    }
681	}
